    "mcq": [
      {
        "question": "Which standard is used to define the atomic mass unit (u)?",
        "options": [
          "A. Hydrogen-1 atom",
          "B. Oxygen-16 atom",
          "C. Carbon-12 atom",
          "D. Nitrogen-14 atom"
        ],
        "answer": "C",
        "explanation": "Carbon-12 is the international standard, assigned exactly 12 u.",
        "marks": 1
